                    <div className="blocker-main static">
                      <strong>{blockerId}</strong>
                      <span>Missing blocker reference</span>
                      <em>Warning</em>
                    </div>
                    <button className="icon-button" onClick={() => removeBlocker(blockerId)} aria-label={`Remove missing blocker ${blockerId}`}>
                      <X size={15} />
