                      ))}
                    </select>
                  </label>
                  <button onClick={() => void linkExistingTicket()} disabled={subticketBusy || !linkSubticketId}>
                    <Plus size={16} />
                    Link
                  </button>
                </div>
              </div>
            )}
          </section>

