.card-title {
  margin-bottom: 8px;
  color: var(--relay-text);
  font-weight: 560;
  line-height: 1.32;
}

.card-excerpt {
  display: -webkit-box;
  overflow: hidden;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 4;
  margin: 0;
  color: rgb(255 255 255 / 66%);
  font-size: var(--relay-text-md);
  line-height: 1.5;
}

.card-meta,
.labels,
.danger-row,
.detail-actions {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.card-meta {
  margin-top: 12px;
  opacity: 0.82;
}

.priority,
.run-pill,
.ticket-type-pill,
.ticket-blocker-pill,
.labels span {
  min-height: 21px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5.5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
}

.run-pill {
  gap: 5px;
}

.run-pill-icon {
  flex: 0 0 auto;
}

.git-metadata {
  min-width: 0;
  max-width: min(100%, 360px);
  min-height: 22px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
  white-space: nowrap;
}

.git-metadata svg {
  flex: 0 0 auto;
}

.git-metadata > span {
  min-width: 0;

}

.detail-header h2 {
  max-width: 100%;
  margin-top: var(--relay-space-2);
  overflow-wrap: anywhere;
  font-size: var(--relay-text-xl);
  font-weight: 580;
  line-height: 1.24;
}

.detail-status-row {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.detail-actions {
  margin-top: var(--relay-space-3);
}

.epic-link-panel {
  margin-top: var(--relay-space-4);
  overflow: hidden;
  border-radius: var(--relay-radius-md);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 4%), transparent),
    var(--relay-surface);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 5%);
}

.epic-link-panel header {
  min-height: 40px;
  padding: 9px 11px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--relay-space-3);
}

.epic-link-panel h3 {
  margin: 0;
  font-size: var(--relay-text-base);
  font-weight: 560;
}

.epic-link-panel header button {
  min-height: 30px;
}

.subticket-list {
  display: grid;
  gap: var(--relay-space-2);
  padding: 0 var(--relay-space-3) var(--relay-space-3);
}

.subticket-list > p {
  margin: 0;
  color: var(--relay-text-muted);
  font-size: var(--relay-text-md);
}

.subticket-item {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: var(--relay-space-2);
  align-items: stretch;
}

.subticket-row {
  width: 100%;
  min-height: 42px;
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto auto auto auto;
  gap: var(--relay-space-2);
  align-items: center;
  justify-content: stretch;
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface-2);
  padding: 8px 10px;
  text-align: left;
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
}

.subticket-row:hover {
  background: var(--relay-surface-hover);
  transform: none;
}

.subticket-row.parent {
  margin: 0 var(--relay-space-3) var(--relay-space-3);
  width: calc(100% - var(--relay-space-3) * 2);
}

.subticket-row strong {
  min-width: 0;
  overflow: hidden;
  color: var(--relay-text);
  font-weight: 560;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.subticket-row span {
  color: var(--relay-text-muted);
  font-size: var(--relay-text-sm);
  white-space: nowrap;
}

.subticket-row em {
  font-style: normal;
  justify-self: end;
}

.blocker-panel {
  margin-top: var(--relay-space-4);
}

.blocker-panel header .ticket-blocker-pill {
  flex-shrink: 0;
}

.blocker-summary-list,
.blocker-picker {
  display: grid;
  gap: var(--relay-space-2);
  padding: 0 var(--relay-space-3) var(--relay-space-3);
}

.blocker-summary-list > p,
.blocker-picker > p {
  margin: 0;
  color: var(--relay-text-muted);
  font-size: var(--relay-text-md);
}

.blocker-picker {
  max-height: 260px;
  overflow-y: auto;
  border-top: 1px solid rgb(255 255 255 / 5%);
  padding-top: var(--relay-space-3);
}

.blocker-row {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: var(--relay-space-2);
  align-items: stretch;
}

.blocker-main,
.blocker-option {
  width: 100%;
  min-height: 42px;
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: var(--relay-space-2);
  align-items: center;
  justify-content: stretch;
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface-2);

  background: var(--relay-surface-2);
  padding: 8px 10px;
  text-align: left;
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
}

.blocker-main:hover {
  background: var(--relay-surface-hover);
  transform: none;
}

.blocker-main.static {
  cursor: default;
}

.blocker-row.active .blocker-main,
.blocker-option.selected {
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px color-mix(in srgb, var(--relay-warning) 20%, transparent);
}

.blocker-row.warning .blocker-main {
  color: var(--relay-danger-text);
  box-shadow:
    var(--relay-inset-highlight),
